SELECT sys_user.user_id as userId, qkyd_device_info.id AS deviceId, sys_user.nick_name as nickName, sys_user.phonenumber as phone, qkyd_device_info.imei as imei, qkyd_device_info.name as deviceName, qkyd_device_info.type as type, qkyd_device_info_extend.battery_level as batteryLevel, qkyd_device_info_extend.last_communication_time as readTime, qkyd_device_info.create_time as createTime FROM qkyd_device_info LEFT JOIN sys_user ON sys_user.user_id = qkyd_device_info.user_id LEFT JOIN qkyd_device_info_extend ON qkyd_device_info.id = qkyd_device_info_extend.device_id
and sys_user.user_id = #{userId} and sys_user.nick_name like concat('%', #{nickName}, '%') and sys_user.phonenumber like concat('%', #{phone}, '%') and qkyd_device_info.imei like concat('%', #{imei}, '%') and qkyd_device_info.type = #{type}
order by qkyd_device_info.id desc

